import { Injectable } from '@angular/core';
import { HttpClient, HttpParams } from '@angular/common/http';
import { Observable } from 'rxjs';

export interface InvestmentItem {
  id?: string;
  date: string;
  type: string;
  amount: number;
  description?: string;
}

@Injectable({
  providedIn: 'root'
})
export class InvestmentsService {
  private apiUrl = 'http://localhost:3001/api/investments';

  constructor(private http: HttpClient) {}

  getAllInvestments(): Observable<InvestmentItem[]> {
    return this.http.get<InvestmentItem[]>(this.apiUrl);
  }

  getInvestmentById(id: string): Observable<InvestmentItem> {
    return this.http.get<InvestmentItem>(`${this.apiUrl}/${id}`);
  }

  getInvestmentsWithLimit(limit: number): Observable<InvestmentItem[]> {
    const params = new HttpParams().set('limit', limit.toString());
    return this.http.get<InvestmentItem[]>(this.apiUrl, { params });
  }

  createInvestment(investment: Omit<InvestmentItem, 'id'>): Observable<InvestmentItem> {
    return this.http.post<InvestmentItem>(this.apiUrl, investment);
  }

  updateInvestment(id: string, investment: Partial<InvestmentItem>): Observable<InvestmentItem> {
    return this.http.put<InvestmentItem>(`${this.apiUrl}/${id}`, investment);
  }

  deleteInvestment(id: string): Observable<void> {
    return this.http.delete<void>(`${this.apiUrl}/${id}`);
  }
}
